/// <summary>
/// Extension of the <c>PurchPackingSlipJournalCreate</c> class for the ETGSPAIN model.
/// </summary>
[ExtensionOf(classStr(PurchPackingSlipJournalCreate))]
final class PurchPackingSlipJournalCreate_ETGSPAIN_Class_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>initJournalLine</c> method to add the Application dimension.
/// </summary>
/// <param name="_parmLine">The PurchLine object.</param>
/// <returns>
/// Returns a <c>Common</c> object.
/// </returns>
public Common initJournalLine(Common _parmLine)
{
    VendPackingSlipTrans    vendPackingSlipTrans    = next initJournalLine(_parmLine);
    PurchParmLine           purchParmLine           = _parmLine;

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        vendPackingSlipTrans.ETGSPAINUnsoldQtyModify = purchParmLine.ETGSPAINUnsoldQtyModify;
    }

    return vendPackingSlipTrans;
}
